+// ─── Speech and Thought Bubble Rendering ─────────────────────────────
+
+/**
+ * Draws a speech bubble above a character at (x, y) with the given text.
+ * The bubble has a rounded rectangle with a tail pointing down.
+ */
+export function drawSpeechBubble(ctx: CanvasRenderingContext2D, x: number, y: number, text: string) {
+  ctx.font = '9px monospace';
+  const paddingX = 6;
+  const paddingY = 6;
+  const tw = ctx.measureText(text).width;
+  const bw = tw + paddingX * 2;
+  const bh = 18;
+  const bx = x - bw / 2;
+  const by = y - bh - 8;
+
+  ctx.fillStyle = '#f0ead6'; // light parchment color for speech
+  ctx.strokeStyle = '#2a2020';
+  ctx.lineWidth = 1.5;
+  roundRect(ctx, bx, by, bw, bh, 4);
+  ctx.fill();
+  ctx.stroke();
+
+  // Tail pointing down center
+  ctx.beginPath();
+  ctx.moveTo(x - 4, by + bh);
+  ctx.lineTo(x, by + bh + 6);
+  ctx.lineTo(x + 4, by + bh);
+  ctx.fillStyle = '#f0ead6';
+  ctx.fill();
+  ctx.strokeStyle = '#2a2020';
+  ctx.stroke();
+
+  ctx.fillStyle = '#1a1020';
+  ctx.fillText(text, bx + paddingX, by + 13);
+}
+
+/**
+ * Draws a thought bubble above a character at (x, y) with the given text.
+ * The bubble has a rounded rectangle with a tail of small circles.
+ */
+export function drawThoughtBubble(ctx: CanvasRenderingContext2D, x: number, y: number, text: string) {
+  ctx.font = '9px monospace';
+  const paddingX = 6;
+  const paddingY = 6;
+  const tw = ctx.measureText(text).width;
+  const bw = tw + paddingX * 2;
+  const bh = 18;
+  const bx = x - bw / 2;
+  const by = y - bh - 8;
+
+  ctx.fillStyle = '#d8e8f8'; // pale blue for thought
+  ctx.strokeStyle = '#2a2020';
+  ctx.lineWidth = 1.5;
+  roundRect(ctx, bx, by, bw, bh, 4);
+  ctx.fill();
+  ctx.stroke();
+
+  // Tail with small circles
+  ctx.fillStyle = '#d8e8f8';
+  ctx.beginPath();
+  ctx.arc(x - 2, by + bh + 10, 2, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.stroke();
+  ctx.beginPath();
+  ctx.arc(x - 6, by + bh + 14, 1.5, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.stroke();
+
+  ctx.fillStyle = '#1a1020';
+  ctx.fillText(text, bx + paddingX, by + 13);
+}
+
